.darma-loader-darma-custom-078 {
  display: inline-flex;
  width: 90px;
  aspect-ratio: 2;
  animation: darma-loader-darma-custom-078-l10-0 1s linear infinite;
}
.darma-loader-darma-custom-078:before,
.darma-loader-darma-custom-078:after {
  content: "";
  flex: 1;
  background: var(--loader-color, #574951);
  clip-path: polygon(50% 0,100% 50%,50% 100%,0 50%);
  animation: darma-loader-darma-custom-078-l10-1 1s linear infinite;
  transform-origin: right;
}
.darma-loader-darma-custom-078:after {
  scale: -1 1;
  translate: -100% 0;
  animation-direction: reverse;
}
@keyframes darma-loader-darma-custom-078-l10-0 {
  0%{translate: 0 -35.35%}
  to{translate: 0  35.35%}
}
@keyframes darma-loader-darma-custom-078-l10-1 {
  0%{rotate: -45deg}
  to{rotate:  45deg}
}

